<?php
namespace App\Http\Controllers\CommandCenter\Customers; use App\Http\Controllers\Controller; use App\Http\Requests\Customers\CustomerAddressRequest; use App\Http\Requests\Customers\CustomerContactRequest; use App\Http\Requests\Customers\StoreCustomerRequest; use App\Http\Requests\Customers\UpdateCustomerRequest; use App\Models\Customers\CustomerAddress; use App\Models\Customers\CustomerContact; use App\Repositories\Customers\CustomerGroupRepository; use App\Repositories\Customers\CustomerRepository; use App\Services\AuditLogger; use App\Services\Customers\CustomerInsightService; use App\Services\Customers\CustomerService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\View\View;
class CustomerController extends Controller { public function index(Request $r,CustomerRepository $repo,CustomerGroupRepository $groups):View{return view('command-center.customers.index',['customers'=>$repo->paginateForCompany($r->user()->company_id,$r->only(['search','status','type','group_id','trashed'])),'groups'=>$groups->options($r->user()->company_id)]);} public function create(Request $r,CustomerGroupRepository $groups):View{return view('command-center.customers.create',['groups'=>$groups->options($r->user()->company_id)]);} public function store(StoreCustomerRequest $r,CustomerService $service,CustomerInsightService $insights):RedirectResponse{$customer=$service->create($r->user(),$r->validated());$insights->calculate($customer);return redirect()->route('customers.show',$customer)->with('status','Customer created.');} public function show(Request $r,CustomerRepository $repo):View{return view('command-center.customers.show',['customer'=>$repo->findForCompany($r->user()->company_id,(int)$r->route('customer'))]);} public function edit(Request $r,CustomerRepository $repo,CustomerGroupRepository $groups):View{return view('command-center.customers.edit',['customer'=>$repo->findForCompany($r->user()->company_id,(int)$r->route('customer')),'groups'=>$groups->options($r->user()->company_id)]);} public function update(UpdateCustomerRequest $r,CustomerRepository $repo,CustomerService $service,CustomerInsightService $insights):RedirectResponse{$customer=$service->update($repo->findForCompany($r->user()->company_id,(int)$r->route('customer')),$r->user(),$r->validated());$insights->calculate($customer);return redirect()->route('customers.show',$customer)->with('status','Customer updated.');} public function destroy(Request $r,CustomerRepository $repo,CustomerService $service):RedirectResponse{$service->delete($repo->findForCompany($r->user()->company_id,(int)$r->route('customer')),$r->user());return back()->with('status','Customer moved to trash.');} public function restore(Request $r,CustomerRepository $repo,CustomerService $service):RedirectResponse{$customer=$service->restore($repo->findForCompany($r->user()->company_id,(int)$r->route('customer'),true),$r->user());return redirect()->route('customers.show',$customer);} public function storeAddress(CustomerAddressRequest $r,CustomerRepository $repo,AuditLogger $audit):RedirectResponse{$customer=$repo->findForCompany($r->user()->company_id,(int)$r->route('customer'));$address=CustomerAddress::create($r->validated()+['company_id'=>$customer->company_id,'customer_id'=>$customer->id]);$audit->record('customer.address.created',$customer,'Customer address added',['address_id'=>$address->id]);return back()->with('status','Address added.');} public function storeContact(CustomerContactRequest $r,CustomerRepository $repo,AuditLogger $audit):RedirectResponse{$customer=$repo->findForCompany($r->user()->company_id,(int)$r->route('customer'));$contact=CustomerContact::create($r->validated()+['company_id'=>$customer->company_id,'customer_id'=>$customer->id]);$audit->record('customer.contact.created',$customer,'Customer contact added',['contact_id'=>$contact->id]);return back()->with('status','Contact added.');} }
